package com.chenboda01.bclockv1;
import android.app.*;import android.os.*;import android.widget.*;import android.graphics.*;import java.text.*;import java.util.*;
public class MainActivity extends Activity{TextView t;Handler h=new Handler();Runnable r=new Runnable(){public void run(){t.setText(new SimpleDateFormat("HH:mm:ss",Locale.US).format(new Date()));h.postDelayed(this,1000);}};public void onCreate(Bundle b){super.onCreate(b);LinearLayout l=new LinearLayout(this);l.setOrientation(LinearLayout.VERTICAL);l.setGravity(17);l.setBackgroundColor(Color.rgb(7,19,30));TextView title=new TextView(this);title.setText("B-Clock V1");title.setTextColor(Color.WHITE);title.setTextSize(30);t=new TextView(this);t.setTextColor(Color.rgb(80,255,157));t.setTextSize(56);Button timer=new Button(this);timer.setText("Timer coming in V1.1");l.addView(title);l.addView(t);l.addView(timer);setContentView(l);r.run();}}
